import{_ as t,c as a,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"初期化: Agent の記憶構築 | opencode-supermemory","description":"/supermemory-init コマンドでコードベースをスキャンし、アーキテクチャと規約を永続記憶に保存する方法を学びます。","frontmatter":{"title":"初期化: Agent の記憶構築 | opencode-supermemory","sidebarTitle":"初期化","subtitle":"プロジェクト初期化：第一印象を確立","description":"/supermemory-init コマンドでコードベースをスキャンし、アーキテクチャと規約を永続記憶に保存する方法を学びます。","tags":["初期化","記憶の生成","ワークフロー"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"ja/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"ja/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),i={name:"ja/supermemoryai/opencode-supermemory/start/initialization/index.md"};function r(n,e,l,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="プロジェクト初期化-第一印象を確立" tabindex="-1">プロジェクト初期化：第一印象を確立 <a class="header-anchor" href="#プロジェクト初期化-第一印象を確立" aria-label="Permalink to &quot;プロジェクト初期化：第一印象を確立&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li><strong>プロジェクトをワンクリックで理解</strong>：Agent が新しい従業員のように、コードベースを能動的に探索し理解します。</li><li><strong>長期記憶を確立</strong>：プロジェクトの技術スタック、アーキテクチャパターン、コーディング規約を自動的に抽出し、Supermemory に保存します。</li><li><strong>繰り返しの説明を排除</strong>：毎回のセッションの開始時に「Bun を使用しています」や「すべてのコンポーネントにテストを書く必要がある」を繰り返す必要がなくなります。</li></ul><h2 id="今の課題" tabindex="-1">今の課題 <a class="header-anchor" href="#今の課題" aria-label="Permalink to &quot;今の課題&quot;">​</a></h2><p>以下のような状況に遭遇したことはありませんか？</p><ul><li><strong>繰り返し作業</strong>：新しいセッションを開始するたびに、プロジェクトの基本情報を伝えるのに多くの時間を費やします。</li><li><strong>コンテキストの忘却</strong>：Agent はプロジェクト固有のディレクトリ構造を頻繁に忘れ、ファイルを間違った場所に作成します。</li><li><strong>規約の不統一</strong>：Agent が書くコードのスタイルが不安定で、時には <code>interface</code>、時には <code>type</code> を使います。</li></ul><h2 id="いつこの方法を使うべきか" tabindex="-1">いつこの方法を使うべきか <a class="header-anchor" href="#いつこの方法を使うべきか" aria-label="Permalink to &quot;いつこの方法を使うべきか&quot;">​</a></h2><ul><li><strong>プラグインのインストール直後</strong>：opencode-supermemory を使用する最初のステップです。</li><li><strong>新しいプロジェクトに着手する場合</strong>：プロジェクトの記憶ライブラリを迅速に構築します。</li><li><strong>大規模なリファクタリング後</strong>：プロジェクトのアーキテクチャが変更された場合、Agent の認識を更新する必要があります。</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件の確認</p><p><a href="./../getting-started/">クイックスタート</a> のインストールと設定の手順が完了済みで、<code>SUPERMEMORY_API_KEY</code> が正しく設定されていることを確認してください。</p></div><h2 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h2><p><code>/supermemory-init</code> コマンドは本質的にはバイナリプログラムではなく、<strong>慎重に設計されたプロンプト（Prompt）</strong> です。</p><p>このコマンドを実行すると、Agent に詳細な「入職ガイド」が送信され、以下を指示します：</p><ol><li><strong>深い調査</strong>：<code>README.md</code>、<code>package.json</code>、Git コミット履歴などを能動的に読み込みます。</li><li><strong>構造化された分析</strong>：プロジェクトの技術スタック、アーキテクチャパターン、暗黙の規約を識別します。</li><li><strong>永続的な保存</strong>：<code>supermemory</code> ツールを使用して、これらの洞察をクラウドデータベースに保存します。</li></ol><div class="info custom-block"><p class="custom-block-title">記憶スコープ</p><p>初期化プロセスでは 2 種類の記憶を区別します：</p><ul><li><strong>Project Scope</strong>：現在のプロジェクトのみに有効（例：ビルドコマンド、ディレクトリ構造）。</li><li><strong>User Scope</strong>：すべてのプロジェクトに有効（例：好みのコードスタイル）。</li></ul></div><h2 id="実践-一緒に作業しましょう" tabindex="-1">実践：一緒に作業しましょう <a class="header-anchor" href="#実践-一緒に作業しましょう" aria-label="Permalink to &quot;実践：一緒に作業しましょう&quot;">​</a></h2><h3 id="ステップ-1-初期化コマンドを実行" tabindex="-1">ステップ 1：初期化コマンドを実行 <a class="header-anchor" href="#ステップ-1-初期化コマンドを実行" aria-label="Permalink to &quot;ステップ 1：初期化コマンドを実行&quot;">​</a></h3><p>OpenCode の入力ボックスに以下のコマンドを入力して送信します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>理由</strong> これにより、定義済みのプロンプトが読み込まれ、Agent の探索モードが起動します。</p><p><strong>期待される出力</strong> Agent が返信を開始し、タスクを理解して調査手順を計画していることを示します。次のように言うかもしれません：&quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="ステップ-2-agent-の探索プロセスを観察" tabindex="-1">ステップ 2：Agent の探索プロセスを観察 <a class="header-anchor" href="#ステップ-2-agent-の探索プロセスを観察" aria-label="Permalink to &quot;ステップ 2：Agent の探索プロセスを観察&quot;">​</a></h3><p>Agent は一連の操作を自動的に実行するので、あなたは見ているだけで大丈夫です。通常、以下を行います：</p><ol><li><strong>設定ファイルの読み込み</strong>：<code>package.json</code>、<code>tsconfig.json</code> などを読み込んで技術スタックを理解します。</li><li><strong>Git 履歴の確認</strong>：<code>git log</code> を実行してコミット規約とアクティブな貢献者を理解します。</li><li><strong>ディレクトリ構造の探索</strong>：<code>ls</code> または <code>list_files</code> を使用してプロジェクトレイアウトを確認します。</li></ol><p><strong>出力例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">消費のヒント</p><p>このプロセスは深い調査であり、多くの Token を消費する可能性があります（通常 50 回以上のツール呼び出し）。完了まで忍耐強くお待ちください。</p></div><h3 id="ステップ-3-生成された記憶を確認" tabindex="-1">ステップ 3：生成された記憶を確認 <a class="header-anchor" href="#ステップ-3-生成された記憶を確認" aria-label="Permalink to &quot;ステップ 3：生成された記憶を確認&quot;">​</a></h3><p>Agent が初期化完了を報告したら、実際に何を記憶したかを確認できます。以下を入力します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 現在のプロジェクトの記憶をリストアップ</span></span></code></pre></div><p>または、生データを確認したい場合はツールを直接呼び出します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>期待される出力</strong> Agent は一連の構造化された記憶をリストアップします。例：</p><table tabindex="0"><thead><tr><th>タイプ</th><th>内容の例</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="ステップ-4-不足箇所を補足-オプション" tabindex="-1">ステップ 4：不足箇所を補足（オプション） <a class="header-anchor" href="#ステップ-4-不足箇所を補足-オプション" aria-label="Permalink to &quot;ステップ 4：不足箇所を補足（オプション）&quot;">​</a></h3><p>Agent が重要な情報を見落とした場合（例：口頭で合意された特定のルール）、手動で補足できます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>覚えておいてください：このプロジェクトでは、すべての日付処理に dayjs ライブラリを使用し、ネイティブな Date は使用禁止です。</span></span></code></pre></div><p><strong>期待される出力</strong> Agent が確認を返信し、この新しいルールを保存するために <code>supermemory(mode: &quot;add&quot;)</code> を呼び出します。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] <code>/supermemory-init</code> を実行後、Agent が自動的に探索タスクを実行しましたか？</li><li>[ ] <code>list</code> コマンドを使用して新しく生成された記憶を確認できますか？</li><li>[ ] 記憶内容は現在のプロジェクトの実際の状況を正確に反映していますか？</li></ul><h2 id="落とし穴の警告" tabindex="-1">落とし穴の警告 <a class="header-anchor" href="#落とし穴の警告" aria-label="Permalink to &quot;落とし穴の警告&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">頻繁に実行しないでください</p><p>初期化は時間がかかり、多くの Token を消費するプロセスです。通常、各プロジェクトで 1 回だけ実行すれば十分です。プロジェクトに大きな変更があった場合のみ再実行が必要です。</p></div><div class="danger custom-block"><p class="custom-block-title">プライバシーの注意</p><p>プラグインは <code>&lt;private&gt;</code> タグの内容を自動的に検閲しますが、初期化プロセス中に Agent は多くのファイルを読み込みます。コードベースにハードコードされたセンシティブなキー（AWS Secret Key など）が含まれていないことを確認してください。それらは「プロジェクト設定」として記憶に保存される可能性があります。</p></div><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p><code>/supermemory-init</code> を通じて、私たちは「見知らぬ人」から「熟練した従業員」への変換を完了しました。これで、Agent はプロジェクトのコアアーキテクチャと規約を記憶し、今後のコーディングタスクでこれらのコンテキストを自動的に活用して、より的確な支援を提供できるようになります。</p><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では <strong><a href="./../../core/context-injection/">自動コンテキスト注入メカニズム</a></strong> を学びます。</p><p>以下のことができるようになります：</p><ul><li>Agent がセッションの開始時にこれらの記憶を「想起」する方法</li><li>特定の記憶の想起をトリガーするキーワードの使用方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>初期化プロンプトの定義</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>記憶ツールの実装</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>：<code>/supermemory-init</code> コマンドの具体的なプロンプト内容を定義し、Agent に調査と記憶の方法を指示します。</li></ul></details>`,50)])])}const g=t(i,[["render",r]]);export{u as __pageData,g as default};
